// ===============================
// DADOS DE ENTRADA
// ===============================

// Webhook (sempre 1 item)
const webhook = $('Webhook').item.json.body;

// Linha do template vinda do Supabase
const template = $input.item.json;

// ===============================
// SEGURANÇAS
// ===============================

if (!template.variables || !Array.isArray(template.variables)) {
  throw new Error('Template sem array de variables no Supabase');
}

// ===============================
// QUEBRA DA LEGENDA
// ===============================

// Usa parágrafos como separador (correto para WhatsApp)
const blocosLegenda = (webhook.legenda_whatsapp || '')
  .split(/\n\s*\n/)
  .map(t => t.trim())
  .filter(Boolean);

// ===============================
// VARIÁVEIS DO TEMPLATE
// ===============================

const variables = template.variables; // ex: ["nome_usuario"]
const totalVars = variables.length;

// ===============================
// MONTA PARAMETROS
// REGRA:
// - Se a variável for nome_usuario → source: nome
// - As demais → vêm da legenda (na ordem)
// ===============================

const parametros = [];
let legendaCursor = 0;

for (let i = 0; i < totalVars; i++) {
  const varName = variables[i];

  if (varName === 'nome_usuario') {
    parametros.push({
      type: 'text',
      source: 'nome'
    });
  } else {
    parametros.push({
      type: 'text',
      source: 'legenda',
      value: blocosLegenda[legendaCursor] || ''
    });
    legendaCursor++;
  }
}

// ===============================
// DEFINE MÍDIA (SE EXISTIR)
// ===============================

let media_type = 'none';
let media_url = null;

if (template.media_type && template.media_type !== 'none') {
  media_type = template.media_type;
  media_url = template.media_url || webhook.imagem1_url || null;
}

// ===============================
// RETORNO FINAL (PARA O SUBFLUXO)
// ===============================

return {
  json: {
    dados_meta: {
      phone_number_id_meta: '782664311604851', 
      template_whatsapp: template.meta_template_name,
      meta_template_id: template.meta_template_id,
      language: template.language || 'pt_BR',
      media_type,
      media_url,
      parametros
    }
  }
};
